package com.bank.service;

import com.bank.model.AccountBalance;
import com.bank.model.BankingTransaction;
import com.bank.model.TransactionRequest;
import com.bank.model.TransactionResponse;

import javax.annotation.Resource;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

@WebService(
    serviceName = "BankingService",
    portName = "BankingServicePort",
    targetNamespace = "http://bank.com/services",
    endpointInterface = "com.bank.service.BankingService"
)
public class BankingServiceImpl implements BankingService {
    
    @Resource
    private WebServiceContext wsContext;
    
    private static final Map<String, BankingTransaction> transactions = new ConcurrentHashMap<>();
    private static final Map<String, BigDecimal> accounts = new ConcurrentHashMap<>();
    
    static {
        accounts.put("ACC001", new BigDecimal("10000.00"));
        accounts.put("ACC002", new BigDecimal("5000.00"));
        accounts.put("ACC003", new BigDecimal("15000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        try {
            validateRequest(request);
            
            String transactionId = UUID.randomUUID().toString();
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
            String timestamp = sdf.format(new Date());
            
            BigDecimal fromBalance = accounts.get(request.getFromAccount());
            if (fromBalance == null) {
                return new TransactionResponse(transactionId, "FAILED", 
                    "Source account not found", timestamp);
            }
            
            if (fromBalance.compareTo(request.getAmount()) < 0) {
                return new TransactionResponse(transactionId, "FAILED", 
                    "Insufficient funds", timestamp);
            }
            
            if (!accounts.containsKey(request.getToAccount())) {
                return new TransactionResponse(transactionId, "FAILED", 
                    "Destination account not found", timestamp);
            }
            
            accounts.put(request.getFromAccount(), 
                fromBalance.subtract(request.getAmount()));
            accounts.put(request.getToAccount(), 
                accounts.get(request.getToAccount()).add(request.getAmount()));
            
            BankingTransaction transaction = new BankingTransaction(
                transactionId,
                request.getFromAccount(),
                request.getToAccount(),
                request.getAmount(),
                request.getCurrency(),
                request.getDescription()
            );
            transaction.setStatus("COMPLETED");
            transactions.put(transactionId, transaction);
            
            return new TransactionResponse(transactionId, "COMPLETED", 
                "Transaction processed successfully", timestamp);
                
        } catch (Exception e) {
            String transactionId = UUID.randomUUID().toString();
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
            return new TransactionResponse(transactionId, "FAILED", 
                "Error processing transaction: " + e.getMessage(), 
                sdf.format(new Date()));
        }
    }

    @Override
    public AccountBalance getAccountBalance(String accountNumber) {
        BigDecimal balance = accounts.get(accountNumber);
        if (balance == null) {
            return new AccountBalance(accountNumber, BigDecimal.ZERO, "USD", "Unknown");
        }
        return new AccountBalance(accountNumber, balance, "USD", "Account Holder");
    }

    @Override
    public TransactionResponse verifyTransaction(String transactionId) {
        BankingTransaction transaction = transactions.get(transactionId);
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss");
        
        if (transaction == null) {
            return new TransactionResponse(transactionId, "NOT_FOUND", 
                "Transaction not found", sdf.format(new Date()));
        }
        
        return new TransactionResponse(
            transaction.getTransactionId(),
            transaction.getStatus(),
            "Transaction verified",
            sdf.format(transaction.getTimestamp())
        );
    }
    
    private void validateRequest(TransactionRequest request) throws Exception {
        if (request.getFromAccount() == null || request.getFromAccount().isEmpty()) {
            throw new Exception("Source account is required");
        }
        if (request.getToAccount() == null || request.getToAccount().isEmpty()) {
            throw new Exception("Destination account is required");
        }
        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new Exception("Invalid amount");
        }
        if (request.getCurrency() == null || request.getCurrency().isEmpty()) {
            throw new Exception("Currency is required");
        }
    }
}

